 60→void ALFPTacticsUnit::BeginPlay()
 61→{
 62→    Super::BeginPlay();
 63→
 64→    // 注册到回合管理器
 65→    if (ALFPTurnManager* TurnManager = GetTurnManager())
 66→    {
 67→        TurnManager->RegisterUnit(this);
 68→    }
 69→
 70→    for (ULFPBetrayalCondition* Condition : BetrayalConditions)
 71→    {
 72→        if (Condition)
 73→        {
 74→            Condition->RegisterCondition(this);
 75→        }
 76→    }
 77→
 78→    FLFPHexCoordinates SpawnPoint = FLFPHexCoordinates(StartCoordinates_Q, StartCoordinates_R);
 79→    SetCurrentCoordinates(SpawnPoint);
 80→
 81→	// 初始化血量
 82→    CurrentHealth = MaxHealth;
 83→	InitializeHealthBar();
 84→
 85→    PlannedSkillIconComponent->SetRelativeLocation(FVector(0, SkillIconTopDist, 0)); // 在血条上方
 86→
 87→    // 如果是敌方单位，创建AI控制器
 88→    if (IsEnemy())
 89→    {
 90→        FActorSpawnParameters SpawnParams;
 91→        SpawnParams.Owner = this;
 92→        SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
 93→
 94→        if (AIControllerClass)
 95→        {
 96→            AIController = GetWorld()->SpawnActor<ALFPAIController>(AIControllerClass, SpawnParams);
 97→            if (AIController)
 98→            {
 99→                AIController->Possess(this);
100→                AIController->SetControlledUnit(this);
101→            }
102→        }
103→    }
104→}
