567→void ALFPTacticsUnit::ChangeAffiliation(EUnitAffiliation NewAffiliation)
568→{
569→	EUnitAffiliation OldAffiliation = Affiliation;
570→	Affiliation = NewAffiliation;
571→
572→    if (NewAffiliation == EUnitAffiliation::UA_Player)
573→    {
574→        if (AIController)
575→        {
576→            AIController->UnPossess();
577→            AIController->Destroy();
578→        }
579→
580→        // 敌人→玩家：记录捕获
581→        if (OldAffiliation == EUnitAffiliation::UA_Enemy)
582→        {
583→            if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
584→            {
585→                GM->RecordCapturedUnit(this);
586→            }
587→        }
588→    }
589→
590→    // 阵营变更后重新检查胜负条件（如最后一个敌人背叛）
591→    if (ALFPTurnManager* TurnManager = GetTurnManager())
592→    {
593→        TurnManager->CheckBattleEnd();
594→    }
595→}
