623→ALFPHexTile* ALFPTacticsUnit::FindBestMovementTile(ALFPTacticsUnit* Target)
624→{
625→    ALFPHexGridManager* GridManager = GetGridManager();
626→    if (!GridManager)
627→    {
628→        return nullptr;
629→    }
630→    // 获取所有可移动位置
631→    MovementRangeTiles = GridManager->GetTilesInRange(GetCurrentTile(), GetCurrentMovePoints());
632→
633→    ALFPHexTile* BestTile = nullptr;
634→    float BestPositionValue = -MAX_FLT;
635→
636→    for (ALFPHexTile* Tile : MovementRangeTiles)
637→    {
638→        // 跳过有单位的格子
639→        if (Tile->GetUnitOnTile()) continue;
640→
641→        float PositionValue = CalculatePositionValue(Tile, Target);
642→        if (PositionValue > BestPositionValue)
643→        {
644→            BestPositionValue = PositionValue;
645→            BestTile = Tile;
646→        }
647→    }
648→
649→    return BestTile;
650→}
