652→float ALFPTacticsUnit::CalculateThreatValue(ALFPTacticsUnit* Target)
653→{
654→    // 威胁值 = 目标攻击力
655→    float ThreatValue = Target->GetAttackPower();
656→
657→    // 距离因素（越近威胁越大）
658→    int32 Distance = FLFPHexCoordinates::Distance(
659→        GetCurrentCoordinates(),
660→        Target->GetCurrentCoordinates()
661→    );
662→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
663→
664→    //// 应用行为数据
665→    //if (BehaviorData)
666→    //{
