 49→void ULFPGameInstance::TransitionToBattle(const FString& BattleLevelName)
 50→{
 51→	if (bIsTransitioning) return;
 52→	bIsTransitioning = true;
 53→
 54→	FString LevelName = BattleLevelName.IsEmpty() ? DefaultBattleLevelName : BattleLevelName;
 55→	UE_LOG(LogTemp, Log, TEXT("切换到战斗关卡: %s"), *LevelName);
 56→
 57→	// 淡出到黑
 58→	UWorld* World = GetWorld();
 59→	if (World)
 60→	{
 61→		APlayerController* PC = World->GetFirstPlayerController();
 62→		if (PC && PC->PlayerCameraManager)
 63→		{
 64→			PC->PlayerCameraManager->StartCameraFade(0.f, 1.f, TransitionFadeDuration, FLinearColor::Black, false, true);
 65→		}
 66→
 67→		// 延迟后加载关卡
 68→		FTimerHandle TimerHandle;
 69→		FString CapturedLevelName = LevelName;
 70→		World->GetTimerManager().SetTimer(TimerHandle, [this, CapturedLevelName]()
 71→		{
 72→			bIsTransitioning = false;
 73→			UGameplayStatics::OpenLevel(this, FName(*CapturedLevelName));
 74→		}, TransitionFadeDuration, false);
 75→	}
 76→	else
 77→	{
 78→		bIsTransitioning = false;
 79→		UGameplayStatics::OpenLevel(this, FName(*LevelName));
 80→	}
 81→}
