294→// ============== 单位升阶 ==============
295→
296→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
297→{
298→	// 统计每个 TypeID 的出现次数
299→	TMap<FName, int32> CountMap;
300→
301→	for (const FLFPUnitEntry& Unit : PartyUnits)
302→	{
303→		if (Unit.IsValid())
304→		{
305→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
306→		}
307→	}
308→	for (const FLFPUnitEntry& Unit : ReserveUnits)
309→	{
310→		if (Unit.IsValid())
311→		{
312→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
313→		}
314→	}
315→
316→	// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
317→	TArray<FLFPUnitEntry> Result;
318→	for (const auto& Pair : CountMap)
319→	{
320→		if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
321→		{
322→			FLFPUnitEntry Entry;
323→			Entry.TypeID = Pair.Key;
324→			Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
325→			Result.Add(Entry);
326→		}
327→	}
328→
329→	return Result;
330→}
331→
332→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
333→	bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
334→{
335→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
336→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
337→
338→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
339→	{
340→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
341→		return false;
342→	}
343→
344→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
345→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
346→
347→	// 验证两个源单位 TypeID 相同
348→	if (UnitA.TypeID != UnitB.TypeID)
349→	{
350→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
351→			*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
352→		return false;
353→	}
354→
355→	// 验证 TargetTypeID 在进化目标列表中
356→	if (!UnitRegistry)
357→	{
358→		UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
359→		return false;
360→	}
361→
362→	TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
363→	if (!Targets.Contains(TargetTypeID))
364→	{
365→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
366→			*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
367→		return false;
368→	}
369→
370→	// 创建进化后的新单位
371→	FLFPUnitEntry NewUnit;
372→	NewUnit.TypeID = TargetTypeID;
373→	NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
374→
375→	// 移除两个源单位（同一数组时先移除大索引避免偏移）
376→	if (bSourceAIsParty == bSourceBIsParty)
377→	{
378→		int32 First = FMath::Max(SourceAIndex, SourceBIndex);
379→		int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
380→		ArrayA.RemoveAt(First);
381→		ArrayA.RemoveAt(Second);
382→	}
383→	else
384→	{
385→		ArrayA.RemoveAt(SourceAIndex);
386→		ArrayB.RemoveAt(SourceBIndex);
387→	}
388→
389→	TryAddUnit(NewUnit);
390→
391→	UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
392→		*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
393→
394→	return true;
395→}
