 573→void ALFPTacticsPlayerController::SelectTile(ALFPHexTile* Tile)
 574→{
 575→    if (!SelectedUnit || !GridManager) return;
 576→
 577→    switch (CurrentControlState)
 578→    {
 579→    case EPlayControlState::MoveState:
 580→        // 检查是否在可移动范围内
 581→        if (MovementRangeTiles.Contains(Tile))
 582→        {
 583→            SelectedTile = Tile;
 584→            ShowPathToSelectedTile();
 585→        }
 586→        else
 587→        {
 588→            SelectedTile = Tile;
 589→            // 清除之前高亮显示的路径
 590→            HidePathToRange();
 591→        }
 592→        break;
 593→    case EPlayControlState::SkillReleaseState:
 594→        SelectedTile = Tile;
 595→        break;
 596→    default:
 597→        break;
 598→    }
 599→}
