1138→void ALFPTacticsPlayerController::PickupDeployedUnit(ALFPTacticsUnit* Unit)
1139→{
1140→    if (!Unit) return;
1141→
1142→    // 找到对应的 PartyIndex
1143→    int32 FoundIndex = DeployedUnits.Find(Unit);
1144→    if (FoundIndex == INDEX_NONE) return;
1145→
1146→    // 清除格子占用
1147→    ALFPHexTile* OldTile = Unit->GetCurrentTile();
1148→    if (OldTile)
1149→    {
1150→        OldTile->SetIsOccupied(false);
1151→        OldTile->SetUnitOnTile(nullptr);
1152→    }
1153→
1154→    // 设置为跟随鼠标的预览
1155→    PlacingUnitPreview = Unit;
1156→    PlacingPartyIndex = FoundIndex;
1157→    bIsPlacingUnit = true;
1158→
1159→    // 清除已布置记录
1160→    DeployedUnits[FoundIndex] = nullptr;
1161→
1162→    // 更新 UI
1163→    if (DeploymentWidget)
1164→    {
1165→        DeploymentWidget->MarkUnitPlaced(FoundIndex, false);
1166→    }
1167→
1168→    UE_LOG(LogTemp, Log, TEXT("拾起已放置的单位（索引 %d）"), FoundIndex);
