 32→            BlackboardComponent->InitializeBlackboard(*BehaviorTree->BlackboardAsset);
 33→        }
 34→
 35→        // 获取网格管理器
 36→        TArray<AActor*> GridManagers;
 37→        UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPHexGridManager::StaticClass(), GridManagers);
 38→        if (GridManagers.Num() > 0)
 39→        {
 40→            GridManager = Cast<ALFPHexGridManager>(GridManagers[0]);
 41→        }
 42→
 43→        // 启动行为树
 44→        RunBehaviorTree(BehaviorTree);
 45→    }
