 74→ALFPTacticsUnit* ALFPAIController::FindBestTarget() const
 75→{
 76→    if (!ControlledUnit || !GridManager) return nullptr;
 77→
 78→    // 获取所有玩家单位
 79→    TArray<AActor*> PlayerUnits;
 80→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
 81→
 82→    ALFPTacticsUnit* BestTarget = nullptr;
 83→    float BestThreatValue = -MAX_FLT;
 84→
 85→    for (AActor* Actor : PlayerUnits)
 86→    {
 87→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
 88→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
 89→        {
 90→            float ThreatValue = CalculateThreatValue(Unit);
 91→            if (ThreatValue > BestThreatValue)
 92→            {
 93→                BestThreatValue = ThreatValue;
 94→                BestTarget = Unit;
 95→            }
 96→        }
 97→    }
 98→
 99→    return BestTarget;
100→}
