107→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), AllUnits);
108→
109→    ALFPTacticsUnit* BestTarget = nullptr;
110→    float BestHatred = -MAX_FLT;
111→
112→    for (AActor* Actor : AllUnits)
113→    {
114→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
115→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
116→        {
117→            float Hatred = Skill->CalculateHatredValue(ControlledUnit, Unit);
118→            if (Hatred > BestHatred)
119→            {
