158→void ALFPTurnManager::BeginEnemyPlanningPhase()
159→{
160→    SetPhase(EBattlePhase::BP_EnemyPlanning);
161→
162→    // 过滤出存活的敌方单位，按速度排序
163→    PlanningOrderEnemies.Empty();
164→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
165→    {
166→        if (Unit && Unit->IsAlive() && Unit->IsEnemy())
167→        {
168→            PlanningOrderEnemies.Add(Unit);
169→        }
170→    }
171→
172→    // 敌方单位已按速度排序（继承自 TurnOrderUnits 的排序）
173→
174→    CurrentPlanningEnemyIndex = 0;
175→
176→    if (PlanningOrderEnemies.Num() == 0)
177→    {
178→        // 没有敌方单位，直接进入行动阶段
179→        EndEnemyPlanningPhase();
180→        return;
181→    }
182→
183→    // 隐藏玩家技能选择UI
184→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
185→    {
186→        PC->HideSkillSelection();
187→    }
188→
189→    // Step 1: 全局技能分配（按优先级分配AP技能）
190→    AllocateEnemySkills();
191→
192→    // Step 2: 按速度顺序移动展示
193→    ProcessNextEnemyPlan();
194→}
195→
196→void ALFPTurnManager::ProcessNextEnemyPlan()
197→{
198→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
199→    {
200→        // 所有敌人规划完毕
201→        EndEnemyPlanningPhase();
202→        return;
203→    }
204→
205→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
206→
207→    // 跳过死亡单位
208→    if (!Enemy || !Enemy->IsAlive())
209→    {
210→        CurrentPlanningEnemyIndex++;
211→        ProcessNextEnemyPlan();
212→        return;
213→    }
214→
215→    ALFPAIController* AIController = Enemy->GetAIController();
216→    if (!AIController)
217→    {
218→        CurrentPlanningEnemyIndex++;
219→        ProcessNextEnemyPlan();
220→        return;
221→    }
222→
223→    // 移动前等待，让玩家观察当前局势
224→    FTimerHandle TimerHandle;
225→    GetWorld()->GetTimerManager().SetTimer(
226→        TimerHandle,
227→        this,
228→        &ALFPTurnManager::ExecuteCurrentEnemyPlan,
229→        EnemyPlanPreMoveDelay,
230→        false
231→    );
232→}
233→
234→void ALFPTurnManager::ExecuteCurrentEnemyPlan()
235→{
236→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
237→    {
238→        EndEnemyPlanningPhase();
239→        return;
240→    }
241→
242→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
243→    if (!Enemy || !Enemy->IsAlive())
244→    {
245→        CurrentPlanningEnemyIndex++;
246→        ProcessNextEnemyPlan();
247→        return;
248→    }
249→
250→    ALFPAIController* AIController = Enemy->GetAIController();
251→    if (!AIController)
252→    {
253→        CurrentPlanningEnemyIndex++;
254→        ProcessNextEnemyPlan();
255→        return;
256→    }
257→
258→    // 创建行动计划，传入预分配的技能
259→    ULFPSkillBase* PreAllocatedSkill = nullptr;
260→    if (ULFPSkillBase** Found = AllocatedSkills.Find(Enemy))
261→    {
262→        PreAllocatedSkill = *Found;
263→    }
264→    FEnemyActionPlan Plan = AIController->CreateActionPlan(PreAllocatedSkill);
265→
266→    // 存储计划
267→    EnemyActionPlans.Add(Plan);
268→    Enemy->SetActionPlan(Plan);
269→
270→    // 推进到下一个敌人
271→    CurrentPlanningEnemyIndex++;
272→
273→    // 如果敌人正在移动，等移动完成后再推进
274→    if (Enemy->bIsMoving)
275→    {
276→        // 记录当前移动中的敌人，回调中需要解绑
277→        PlanningMovingEnemy = Enemy;
278→        Enemy->OnMoveFinished.AddDynamic(this, &ALFPTurnManager::OnEnemyPlanMoveComplete);
279→    }
280→    else
281→    {
282→        // 没有移动，直接推进下一个敌人
283→        ProcessNextEnemyPlan();
284→    }
285→}
