135→float ULFPSkillBase::CalculateHatredValue_Implementation(ALFPTacticsUnit* Caster, ALFPTacticsUnit* Target) const
136→{
137→    if (!Caster || !Target) return 0.0f;
138→
139→    // 基础仇恨 = 目标攻击力（威胁越大越优先打）
140→    float Hatred = (float)Target->GetAttackPower();
141→
142→    // 距离系数（越近仇恨越高）
143→    int32 Dist = FLFPHexCoordinates::Distance(
144→        Caster->GetCurrentCoordinates(),
145→        Target->GetCurrentCoordinates()
146→    );
147→    float DistanceFactor = 1.0f / FMath::Max(Dist, 1);
148→
149→    return Hatred * DistanceFactor;
150→}
